mapper.select:
SELECT id, publication_no AS publicationNo, title, applicant, `abstract` AS patentAbstract, publication_date AS publicationDate, source_type AS sourceType, parse_status AS parseStatus, created_at AS createdAt FROM patent
AND parse_status = #{parseStatus}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR publication_no LIKE CONCAT('%', #{keyword}, '%') OR applicant LIKE CONCAT('%', #{keyword}, '%') OR `abstract` LIKE CONCAT('%', #{keyword}, '%'))
AND created_by = #{userId}
ORDER BY created_at DESC
